import { useEffect, useRef } from "react";
import { useChatStore } from "../store/useChatStore";

import ChatHeader from "./ChatHeader";
import MessageInput from "./MessageInput";
import MessageSkeleton from "./skeletons/MessageSkeleton";
import { useAuthStore } from "../store/useAuthStore";
import { formatMessageTime } from "../lib/utils";
import { motion, AnimatePresence } from "framer-motion";

const ChatContainer = () => {
    const {
        messages,
        getMessages,
        isMessagesLoading,
        selectedUser,
        selectedGroup,
        subscribeToMessages,
        unsubscribeFromMessages,
        markMessagesAsRead,
    } = useChatStore();
    const { authUser } = useAuthStore();
    const messageEndRef = useRef(null);

    useEffect(() => {
        if (selectedUser) {
            getMessages(selectedUser._id);
            markMessagesAsRead(selectedUser._id);
        } else if (selectedGroup) {
            // getMessages(selectedGroup._id); // Assuming backend handles group messages separately
        }

        subscribeToMessages();

        return () => unsubscribeFromMessages();
    }, [selectedUser, selectedGroup, getMessages, subscribeToMessages, unsubscribeFromMessages, markMessagesAsRead]);

    useEffect(() => {
        if (messageEndRef.current && messages) {
            messageEndRef.current.scrollIntoView({ behavior: "smooth" });
        }
    }, [messages]);

    if (isMessagesLoading) {
        return (
            <div className="flex-1 flex flex-col overflow-auto">
                <ChatHeader />
                <MessageSkeleton />
                <MessageInput />
            </div>
        );
    }

    return (
        <div className="flex-1 flex flex-col overflow-auto">
            <ChatHeader />

            <div className="flex-1 overflow-y-auto p-4 space-y-4">
                <AnimatePresence>
                    {messages.map((message) => (
                        <motion.div
                            key={message._id}
                            initial={{ opacity: 0, y: 20, scale: 0.95 }}
                            animate={{ opacity: 1, y: 0, scale: 1 }}
                            exit={{ opacity: 0, scale: 0.9 }}
                            transition={{ duration: 0.2 }}
                            className={`chat ${message.senderId === authUser._id ? "chat-end" : "chat-start"}`}
                            ref={messageEndRef}
                        >
                            <div className=" chat-image avatar">
                                <div className="size-10 rounded-full border">
                                    <img
                                        src={
                                            message.senderId === authUser._id
                                                ? authUser.profilePic || "/avatar.png"
                                                : selectedUser.profilePic || "/avatar.png"
                                        }
                                        alt="profile pic"
                                    />
                                </div>
                            </div>
                            <div className="chat-header mb-1">
                                <time className="text-xs opacity-50 ml-1">
                                    {formatMessageTime(message.createdAt)}
                                </time>
                            </div>
                            <div className="chat-bubble flex flex-col">
                                {message.image && (
                                    <img
                                        src={message.image}
                                        alt="Attachment"
                                        className="sm:max-w-[200px] rounded-md mb-2"
                                    />
                                )}
                                {message.text && <p>{message.text}</p>}
                            </div>
                            {message.senderId === authUser._id && message.isRead && (
                                <div className="chat-footer opacity-50 text-xs flex items-center gap-1">
                                    Seen
                                </div>
                            )}
                        </motion.div>
                    ))}
                </AnimatePresence>
            </div>

            <MessageInput />
        </div>
    );
};
export default ChatContainer;

import { useEffect, useState } from "react";
import { useChatStore } from "../store/useChatStore";
import { useAuthStore } from "../store/useAuthStore";
import SidebarSkeleton from "./skeletons/SidebarSkeleton";
import { MessageSquare, Search, Users } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

const Sidebar = () => {
    const {
        getUsers,
        users,
        groups,
        getGroups,
        selectedUser,
        setSelectedUser,
        selectedGroup,
        setSelectedGroup,
        isUsersLoading,
        searchUsers,
        sendChatRequest,
        handleChatRequest
    } = useChatStore();

    const { onlineUsers, authUser } = useAuthStore();
    const [showOnlineOnly, setShowOnlineOnly] = useState(false);
    const [searchQuery, setSearchQuery] = useState("");

    useEffect(() => {
        getUsers();
        getGroups();
    }, [getUsers, getGroups]);

    const handleSearch = (e) => {
        e.preventDefault();
        if (searchQuery.trim()) {
            searchUsers(searchQuery);
        } else {
            getUsers();
        }
    };

    const filteredUsers = showOnlineOnly
        ? users.filter((user) => onlineUsers.includes(user._id))
        : users;

    if (isUsersLoading) return <SidebarSkeleton />;

    return (
        <aside className="h-full w-20 lg:w-72 border-r border-base-300 flex flex-col transition-all duration-200">
            <div className="border-b border-base-300 w-full p-5">
                <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center gap-2">
                        <Users className="size-6" />
                        <span className="font-medium hidden lg:block">Contacts</span>
                    </div>
                </div>

                {/* Search Bar */}
                <form onSubmit={handleSearch} className="hidden lg:block mb-4">
                    <div className="relative">
                        <input
                            type="text"
                            placeholder="Search users..."
                            className="input input-bordered input-sm w-full pl-8"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                        <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 size-4 text-zinc-500" />
                    </div>
                </form>

                {/* Chat Requests Section */}
                {authUser?.chatRequests?.some(r => r.status === 'pending') && (
                    <div className="hidden lg:block mb-4 p-2 bg-primary/10 rounded-lg">
                        <p className="text-xs font-bold mb-2">Pending Requests</p>
                        {authUser.chatRequests.filter(r => r.status === 'pending').map(req => (
                            <div key={req._id} className="flex items-center justify-between gap-2 mb-2 last:mb-0">
                                <span className="text-xs truncate">New Chat Request</span>
                                <div className="flex gap-1">
                                    <button
                                        onClick={() => handleChatRequest(req._id, 'accepted')}
                                        className="btn btn-xs btn-success"
                                    >✓</button>
                                    <button
                                        onClick={() => handleChatRequest(req._id, 'rejected')}
                                        className="btn btn-xs btn-error"
                                    >✕</button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {/* Groups Section Header */}
                <div className="hidden lg:flex items-center justify-between mb-2">
                    <span className="text-xs font-bold uppercase text-zinc-500">Groups</span>
                    <button
                        className="btn btn-xs btn-ghost text-primary text-xs"
                        onClick={() => document.getElementById('group_modal').showModal()}
                    >+ New</button>
                </div>

                <div className="hidden lg:block space-y-1 mb-4 overflow-y-auto max-h-40">
                    <AnimatePresence>
                        {groups.map((group, index) => (
                            <motion.button
                                key={group._id}
                                initial={{ opacity: 0, x: -10 }}
                                animate={{ opacity: 1, x: 0 }}
                                transition={{ delay: index * 0.05 }}
                                onClick={() => setSelectedGroup(group)}
                                className={`
                                w-full p-2 flex items-center gap-3
                                hover:bg-base-300 transition-colors rounded-lg
                                ${selectedGroup?._id === group._id ? "bg-base-300 ring-1 ring-base-300" : ""}
                            `}
                            >
                                <div className="size-8 rounded-lg bg-primary/10 flex items-center justify-center overflow-hidden">
                                    {group.image ? (
                                        <img src={group.image} alt={group.name} className="size-full object-cover" />
                                    ) : (
                                        <Users className="size-4 text-primary" />
                                    )}
                                </div>
                                <span className="text-sm font-medium truncate">{group.name}</span>
                            </motion.button>
                        ))}
                    </AnimatePresence>
                    {groups.length === 0 && <p className="text-xs text-zinc-500 px-2 italic">No groups joined</p>}
                </div>

                {/* Online filter toggle */}
                <div className="mt-3 hidden lg:flex items-center gap-2">
                    <label className="cursor-pointer flex items-center gap-2">
                        <input
                            type="checkbox"
                            checked={showOnlineOnly}
                            onChange={(e) => setShowOnlineOnly(e.target.checked)}
                            className="checkbox checkbox-sm"
                        />
                        <span className="text-sm">Show online only</span>
                    </label>
                    <span className="text-xs text-zinc-500">({onlineUsers.length > 0 ? onlineUsers.length - 1 : 0} online)</span>
                </div>
            </div>

            <div className="overflow-y-auto w-full py-3">
                <p className="px-5 py-2 text-xs font-bold lg:block hidden uppercase text-zinc-500">Direct Messages</p>
                <div className="space-y-1">
                    <AnimatePresence>
                        {filteredUsers.map((user, index) => (
                            <motion.button
                                key={user._id}
                                initial={{ opacity: 0, x: -20 }}
                                animate={{ opacity: 1, x: 0 }}
                                transition={{ delay: index * 0.05 }}
                                onClick={() => setSelectedUser(user)}
                                className={`
                                    w-full p-3 flex items-center gap-3
                                    hover:bg-base-300 transition-colors
                                    ${selectedUser?._id === user._id ? "bg-base-300 ring-1 ring-base-300" : ""}
                                `}
                            >
                                <div className="relative mx-auto lg:mx-0">
                                    <img
                                        src={user.profilePic || "/avatar.png"}
                                        alt={user.fullName}
                                        className="size-12 object-cover rounded-full"
                                    />
                                    {onlineUsers.includes(user._id) && (
                                        <span
                                            className="absolute bottom-0 right-0 size-3 bg-green-500 
                                            ring-2 ring-zinc-900 rounded-full"
                                        />
                                    )}
                                </div>

                                {/* User info - only visible on larger screens */}
                                <div className="hidden lg:flex flex-1 items-center justify-between min-w-0">
                                    <div className="text-left">
                                        <div className="font-medium truncate">{user.fullName}</div>
                                        <div className="text-sm text-zinc-400">
                                            {onlineUsers.includes(user._id) ? "Online" : "Offline"}
                                        </div>
                                    </div>

                                    <button
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            sendChatRequest(user._id);
                                        }}
                                        className="btn btn-xs btn-ghost text-primary hover:bg-primary/20"
                                        title="Send Chat Request"
                                    >
                                        <MessageSquare className="size-4" />
                                    </button>
                                </div>
                            </motion.button>
                        ))}
                    </AnimatePresence>
                </div>

                {filteredUsers.length === 0 && (
                    <div className="text-center text-zinc-500 py-4">No users found</div>
                )}
            </div>
        </aside>
    );
};
export default Sidebar;

import { useState } from "react";
import { useAuthStore } from "../store/useAuthStore";
import AuthImagePattern from "../components/AuthImagePattern";
import { Link } from "react-router-dom";
import { Eye, EyeOff, Loader2, Lock, Mail, MessageSquare } from "lucide-react";
import { motion } from "framer-motion";

const LoginPage = () => {
    const [showPassword, setShowPassword] = useState(false);
    const [formData, setFormData] = useState({
        email: "",
        password: "",
    });
    const { login, isLoggingIn } = useAuthStore();

    const handleSubmit = async (e) => {
        e.preventDefault();
        login(formData);
    };

    return (
        <div className="min-h-screen pt-16 flex items-center justify-center p-4">
            <motion.div
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                className="glass-premium rounded-3xl overflow-hidden max-w-md w-full"
            >
                {/* Left Side - Form */}
                <div className="flex flex-col justify-center items-center p-8 sm:p-16 lg:p-20">
                    <div className="w-full max-w-sm space-y-8">
                        {/* Logo */}
                        <div className="text-center mb-8">
                            <div className="flex flex-col items-center gap-2 group">
                                <div
                                    className="w-12 h-12 rounded-xl bg-primary/10 flex items-center justify-center group-hover:bg-primary/20 transition-colors"
                                >
                                    <MessageSquare className="w-6 h-6 text-primary" />
                                </div>
                                <h1 className="text-2xl font-bold mt-2">Welcome Back</h1>
                                <p className="text-base-content/60">Sign in to your account</p>
                            </div>
                        </div>

                        {/* Form */}
                        <form onSubmit={handleSubmit} className="space-y-6">
                            <div className="form-control">
                                <label className="label">
                                    <span className="label-text font-medium">Email</span>
                                </label>
                                <div className="relative">
                                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                        <Mail className="h-5 w-5 text-base-content/40" />
                                    </div>
                                    <input
                                        type="email"
                                        className="input-premium w-full pl-10"
                                        placeholder="you@example.com"
                                        value={formData.email}
                                        onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                    />
                                </div>
                            </div>

                            <div className="form-control">
                                <label className="label">
                                    <span className="label-text font-medium">Password</span>
                                </label>
                                <div className="relative">
                                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                        <Lock className="h-5 w-5 text-base-content/40" />
                                    </div>
                                    <input
                                        type={showPassword ? "text" : "password"}
                                        className="input-premium w-full pl-10"
                                        placeholder="••••••••"
                                        value={formData.password}
                                        onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                                    />
                                    <button
                                        type="button"
                                        className="absolute inset-y-0 right-0 pr-3 flex items-center"
                                        onClick={() => setShowPassword(!showPassword)}
                                    >
                                        {showPassword ? (
                                            <EyeOff className="h-5 w-5 text-base-content/40" />
                                        ) : (
                                            <Eye className="h-5 w-5 text-base-content/40" />
                                        )}
                                    </button>
                                </div>
                            </div>

                            <button type="submit" className="btn-premium w-full" disabled={isLoggingIn}>
                                {isLoggingIn ? (
                                    <>
                                        <Loader2 className="h-5 w-5 animate-spin" />
                                        Loading...
                                    </>
                                ) : (
                                    "Sign in"
                                )}
                            </button>
                        </form>

                        <div className="text-center">
                            <p className="text-base-content/60">
                                Don&apos;t have an account?{" "}
                                <Link to="/signup" className="link link-primary">
                                    Create account
                                </Link>
                            </p>
                        </div>
                    </div>
                </div>
            </motion.div>
        </div>
    );
};
export default LoginPage;

import { useState } from "react";
import { useAuthStore } from "../store/useAuthStore";
import { Eye, EyeOff, Loader2, Lock, Mail, MessageSquare, User } from "lucide-react";
import { Link } from "react-router-dom";
import AuthImagePattern from "../components/AuthImagePattern";
import toast from "react-hot-toast";
import { motion } from "framer-motion";

const SignUpPage = () => {
    const [showPassword, setShowPassword] = useState(false);
    const [formData, setFormData] = useState({
        fullName: "",
        email: "",
        password: "",
    });

    const { signup, isSigningUp } = useAuthStore();

    const validateForm = () => {
        if (!formData.fullName.trim()) return toast.error("Full name is required");
        if (!formData.email.trim()) return toast.error("Email is required");
        if (!/\S+@\S+\.\S+/.test(formData.email)) return toast.error("Invalid email format");
        if (!formData.password) return toast.error("Password is required");
        if (formData.password.length < 6) return toast.error("Password must be at least 6 characters");

        return true;
    };

    const handleSubmit = (e) => {
        e.preventDefault();

        const success = validateForm();

        if (success === true) signup(formData);
    };

    return (
        <div className="min-h-screen pt-16 flex items-center justify-center p-4">
            <motion.div
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                className="glass-premium rounded-3xl overflow-hidden max-w-md w-full"
            >
                {/* left side */}
                <div className="flex flex-col justify-center items-center p-8 sm:p-16 lg:p-20">
                    <div className="w-full max-w-sm space-y-8">
                        {/* LOGO */}
                        <div className="text-center mb-8">
                            <div className="flex flex-col items-center gap-2 group">
                                <div
                                    className="size-12 rounded-xl bg-primary/10 flex items-center justify-center 
                group-hover:bg-primary/20 transition-colors"
                                >
                                    <MessageSquare className="size-6 text-primary" />
                                </div>
                                <h1 className="text-2xl font-bold mt-2">Create Account</h1>
                                <p className="text-base-content/60">Get started with your free account</p>
                            </div>
                        </div>

                        <form onSubmit={handleSubmit} className="space-y-6">
                            <div className="form-control">
                                <label className="label">
                                    <span className="label-text font-medium">Full Name</span>
                                </label>
                                <div className="relative">
                                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                        <User className="size-5 text-base-content/40" />
                                    </div>
                                    <input
                                        type="text"
                                        className="input-premium w-full pl-10"
                                        placeholder="John Doe"
                                        value={formData.fullName}
                                        onChange={(e) => setFormData({ ...formData, fullName: e.target.value })}
                                    />
                                </div>
                            </div>

                            <div className="form-control">
                                <label className="label">
                                    <span className="label-text font-medium">Email</span>
                                </label>
                                <div className="relative">
                                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                        <Mail className="size-5 text-base-content/40" />
                                    </div>
                                    <input
                                        type="email"
                                        className="input-premium w-full pl-10"
                                        placeholder="you@example.com"
                                        value={formData.email}
                                        onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                    />
                                </div>
                            </div>

                            <div className="form-control">
                                <label className="label">
                                    <span className="label-text font-medium">Password</span>
                                </label>
                                <div className="relative">
                                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                        <Lock className="size-5 text-base-content/40" />
                                    </div>
                                    <input
                                        type={showPassword ? "text" : "password"}
                                        className="input-premium w-full pl-10"
                                        placeholder="••••••••"
                                        value={formData.password}
                                        onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                                    />
                                    <button
                                        type="button"
                                        className="absolute inset-y-0 right-0 pr-3 flex items-center"
                                        onClick={() => setShowPassword(!showPassword)}
                                    >
                                        {showPassword ? (
                                            <EyeOff className="size-5 text-base-content/40" />
                                        ) : (
                                            <Eye className="size-5 text-base-content/40" />
                                        )}
                                    </button>
                                </div>
                            </div>

                            <button type="submit" className="btn-premium w-full" disabled={isSigningUp}>
                                {isSigningUp ? (
                                    <>
                                        <Loader2 className="size-5 animate-spin" />
                                        Loading...
                                    </>
                                ) : (
                                    "Create Account"
                                )}
                            </button>
                        </form>

                        <div className="text-center">
                            <p className="text-base-content/60">
                                Already have an account?{" "}
                                <Link to="/login" className="link link-primary">
                                    Sign in
                                </Link>
                            </p>
                        </div>
                    </div>
                </div>
            </motion.div>
        </div>
    );
};
export default SignUpPage;
